// Solution
function solve(html) {
  let tags = html.match(/<a[^>]*>/g);
  for (let tag of tags) {
    let hrefIndex = tag.indexOf('href');
    if (hrefIndex === -1 || tag.indexOf('href', hrefIndex + 5) === -1) {
      return false;
    }
  }
  return true;
}

