import re

class Solution:
  def solve(self, html: str) -> bool:
    tags = re.findall(r'<a[^>]*>', html)
    for tag in tags:
      hrefIndex = tag.find('href')
      if hrefIndex === -1 or tag.find('href', hrefIndex + 5) === -1:
        return False
    return True
